+#[test]
+fn strict_mode_getpwuid_returns_null_for_invalid_uid() {
+    with_mode_and_passwd("strict", FIXTURE, || {
+        let pw = unsafe { getpwuid(99999) };
+        assert!(
+            pw.is_null(),
+            "strict mode: getpwuid for nonexistent uid should return null"
+        );
+    });
+}
